const releases = $input.all().map(item => item.json);
const total = releases.length;

const avg = key => {
  if (total === 0) return 0;
  return Math.round(
    releases.reduce((sum, r) => sum + Number(r[key] || 0), 0) / total
  );
};

const countBy = (key, value) =>
  releases.filter(r => r[key] === value).length;

const allBlockers = releases.flatMap(r => r.criticalBlockers || []);
const allActions = releases.flatMap(r => r.requiredActions || []);

const frequency = arr => {
  const map = {};
  for (const item of arr) {
    if (!item) continue;
    map[item] = (map[item] || 0) + 1;
  }
  return Object.entries(map)
    .sort((a, b) => b[1] - a[1])
    .map(([name, count]) => ({ name, count }));
};

const latestRelease = releases[0] || null;

const domainAverages = {
  security: avg("securityScore"),
  performance: avg("performanceScore"),
  business: avg("businessScore"),
  observability: avg("observabilityScore"),
  reliability: avg("reliabilityScore"),
  compliance: avg("complianceScore")
};

const weakestDomain =
  Object.entries(domainAverages)
    .sort((a, b) => a[1] - b[1])[0]?.[0] || "UNKNOWN";

const strongestDomain =
  Object.entries(domainAverages)
    .sort((a, b) => b[1] - a[1])[0]?.[0] || "UNKNOWN";

return {
  generatedAt: new Date().toISOString(),

  summary: {
    totalReleases: total,
    averageConfidence: avg("releaseConfidenceScore"),
    averageRiskScore: avg("overallRiskScore"),
    goCount: countBy("releaseRecommendation", "GO"),
    goWithRiskCount: countBy("releaseRecommendation", "GO_WITH_RISK"),
    noGoCount: countBy("releaseRecommendation", "NO_GO"),
    highRiskCount: countBy("riskLevel", "HIGH"),
    mediumRiskCount: countBy("riskLevel", "MEDIUM"),
    lowRiskCount: countBy("riskLevel", "LOW"),
    weakestDomain,
    strongestDomain
  },

  domainScores: domainAverages,

  latestRelease,

  topBlockers: frequency(allBlockers).slice(0, 5),

  topRequiredActions: frequency(allActions).slice(0, 5),

  executiveReport: {
    title: "Executive Release Readiness Report",
    status:
      total === 0
        ? "NO_DATA"
        : avg("releaseConfidenceScore") >= 85
        ? "HEALTHY"
        : avg("releaseConfidenceScore") >= 60
        ? "NEEDS_ATTENTION"
        : "CRITICAL",
    summary:
      total === 0
        ? "No release data available yet."
        : `Across ${total} release analyses, the average release confidence is ${avg(
            "releaseConfidenceScore"
          )}%. The weakest domain is ${weakestDomain}.`,
    recommendation:
      total === 0
        ? "Run release analyses to generate reports."
        : countBy("releaseRecommendation", "NO_GO") > 0
        ? "Prioritize fixing blockers from NO_GO releases before production deployment."
        : "Continue monitoring release quality and domain risk trends."
  },

  reports: {
    securityReport: {
      averageSecurityScore: avg("securityScore"),
      highRiskSecurityItems: releases.filter(
        r => r.securityRiskLevel === "HIGH"
      ).length
    },
    performanceReport: {
      averagePerformanceScore: avg("performanceScore"),
      highRiskPerformanceItems: releases.filter(
        r => r.performanceRiskLevel === "HIGH"
      ).length
    },
    complianceReport: {
      averageComplianceScore: avg("complianceScore"),
      highRiskComplianceItems: releases.filter(
        r => r.complianceRiskLevel === "HIGH"
      ).length
    },
    qaReport: {
      averageQAReadiness: Math.round(
        releases.reduce(
          (sum, r) => sum + Number(r.releaseMetrics?.qaReadiness || 0),
          0
        ) / (total || 1)
      ),
      noTestingBlockers: allBlockers.filter(b =>
        String(b).toLowerCase().includes("testing")
      ).length
    }
  }
};
